const base = $item(0).$node['Normalize'].json;
const raw =
  $json?.text ||
  $json?.response?.text ||
  $json?.choices?.[0]?.message?.content ||
  '';

const fallbackAnalysis = {
  resumo: 'LLM nao retornou conteudo estruturado.',
  viabilidade: { nivel: 'Media', justificativa: 'Resposta vazia do modelo.' },
  impactos: {},
  criterios_aceite_mapeados: [],
  riscos: ['Sem resposta valida do LLM'],
  duvidas: ['Reexecutar analise']
};

if (!raw || typeof raw !== 'string') {
  return [{
    ...base,
    analysis: fallbackAnalysis,
    analysis_raw: {},
    llm_raw_text: ''
  }];
}

let parsed;
let cleaned = raw;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  const fence = '```';
  cleaned = raw
    .replace(fence + 'json', '')
    .replaceAll(fence, '')
    .trim();

  try {
    parsed = JSON.parse(cleaned);
  } catch (_error) {
    parsed = {
      resumo: cleaned.slice(0, 6000) || 'Resposta nao-JSON do LLM.',
      viabilidade: { nivel: 'Media', justificativa: 'Modelo nao retornou JSON valido.' },
      impactos: {},
      criterios_aceite_mapeados: [],
      riscos: ['Falha ao parsear JSON do LLM'],
      duvidas: ['Ajustar prompt para resposta JSON estrita']
    };
  }
}

const first = (...values) => values.find((v) => v !== undefined && v !== null);
const asArray = (value) => {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null || value === '') return [];
  return [value];
};
const asObject = (value) => (value && typeof value === 'object' && !Array.isArray(value) ? value : {});

const normalizeChange = (change) => {
  if (typeof change === 'string') {
    return {
      descricao: change,
      testes: [],
      criterios_aceite: []
    };
  }

  const c = asObject(change);
  return {
    descricao: String(first(c.descricao, c.desc, c.description, '') || ''),
    testes: asArray(first(c.testes, c.tests, c.test_steps, [])).map((x) => String(x || '').trim()).filter(Boolean),
    criterios_aceite: asArray(first(c.criterios_aceite, c.acceptance_criterias, c.acceptance_criteria, [])).map((x) => String(x || '').trim()).filter(Boolean)
  };
};

const normalizeImpactRepo = (repoImpact) => {
  const i = asObject(repoImpact);
  return {
    impacto: i.impacto === true || i.has_impact === true || i.impact === true,
    mudancas: asArray(first(i.mudancas, i.changes, [])).map(normalizeChange),
    riscos: asArray(first(i.riscos, i.risks, [])).map((x) => String(x || '').trim()).filter(Boolean),
    duvidas: asArray(first(i.duvidas, i.doubts, i.questions, [])).map((x) => String(x || '').trim()).filter(Boolean),
    itens: asArray(first(i.itens, i.items, [])).map((x) => String(x || '').trim()).filter(Boolean)
  };
};

const rawImpacts = asObject(first(parsed?.impactos, parsed?.impacts, parsed?.impact, {}));
const impacts = {};
for (const [key, value] of Object.entries(rawImpacts)) {
  impacts[key] = normalizeImpactRepo(value);
}

const criteriaMapped = [];
const repoRisks = [];
const repoDoubts = [];
for (const [repoName, info] of Object.entries(impacts)) {
  const impactInfo = asObject(info);
  const changes = asArray(impactInfo.mudancas);
  const riscos = asArray(impactInfo.riscos);
  const duvidas = asArray(impactInfo.duvidas);

  for (const r of riscos) {
    if (r) repoRisks.push(String(r));
  }

  for (const d of duvidas) {
    if (d) repoDoubts.push(String(d));
  }

  for (const change of changes) {
    const c = asObject(change);
    const criterios = asArray(c.criterios_aceite);
    const testes = asArray(c.testes);
    for (const criterio of criterios) {
      criteriaMapped.push({
        criterio: String(criterio || '').trim(),
        repos: [repoName],
        teste_sugerido: String(testes[0] || '').trim()
      });
    }
  }
}

const normalized = {
  resumo: first(parsed?.resumo, parsed?.summary, parsed?.executive_summary, parsed?.overview, ''),
  viabilidade: asObject(first(parsed?.viabilidade, parsed?.viability, parsed?.feasibility, {})),
  impactos: impacts,
  criterios_aceite_mapeados: asArray(
    first(
      parsed?.criterios_aceite_mapeados,
      parsed?.acceptance_criteria_mapped,
      parsed?.mapped_acceptance_criteria,
      parsed?.acceptanceCriteriaMapped,
      criteriaMapped
    )
  ),
  riscos: asArray(first(parsed?.riscos, parsed?.risks, parsed?.main_risks, repoRisks)),
  duvidas: asArray(first(parsed?.duvidas, parsed?.questions, parsed?.open_questions, parsed?.openQuestions, repoDoubts))
};

if (!normalized.resumo && Object.keys(asObject(parsed)).length > 0) {
  normalized.resumo = 'Analise recebida do LLM (estrutura fora do padrao esperado).';
}

return [{
  ...base,
  analysis: normalized,
  analysis_raw: asObject(parsed),
  llm_raw_text: cleaned
}];

const analysisId = Number($json.impact_analysis_id);

const q = 'analysis_id=' + encodeURIComponent(String(Number.isFinite(analysisId) ? analysisId : ''));
const implementUrl = 'http://localhost:5678/webhook/fastroute-impact-decision?' + q;

return [{
  analysis_id: Number.isFinite(analysisId) ? analysisId : null,
  aprovar_url: implementUrl,
  mensagem: 'Analise registrada. Clique em Implementar changes para disparar o Governance.'
}];

const q = $json.query || {};

const toSafeNumber = (value) => {
  if (value === undefined || value === null) return NaN;
  const s = String(value).replace(/^\uFEFF/, '').trim();
  if (!s) return NaN;
  const n = Number(s);
  return Number.isFinite(n) ? n : NaN;
};

const analysisId = toSafeNumber(q.analysis_id ?? q.impact_analysis_id ?? q.id);

return [{
  approved: Number.isFinite(analysisId),
  analysis_id: Number.isFinite(analysisId) ? analysisId : null,
  owner: 'oliversoft-tech',
  repo: 'fastroute-changemanagement',
  github_token: 'COLE_SEU_GITHUB_TOKEN_AQUI',
  deploy_api: false,
  domain_ref: 'main',
  api_ref: 'main',
  mobile_ref: 'main',
  mobile_profile: 'preview',
  parse_error: Number.isFinite(analysisId) ? null : 'analysis_id invalido ou ausente no querystring'
}];

const base = $items('Parse LLM JSON', 0, 0)?.[0]?.json || {};
const impactInsert = $items('Insert Impact Analysis', 0, 0)?.[0]?.json || {};
const analysis = base.analysis || {};
const impacts = analysis.impactos || analysis.impacts || {};
const analysisId = impactInsert.id || null;

const normalize = (v) => String(v || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[_\s]+/g, '-')
  .trim();

const asObj = (v) => (v && typeof v === 'object' && !Array.isArray(v) ? v : {});
const toArray = (v) => {
  if (Array.isArray(v)) return v;
  if (v === undefined || v === null || v === '') return [];
  return [v];
};

const toSafeNumber = (value) => {
  if (value === undefined || value === null) return NaN;
  const s = String(value).replace(/^\uFEFF/, '').trim();
  if (!s) return NaN;
  const n = Number(s);
  return Number.isFinite(n) ? n : NaN;
};

const normalizeChange = (change) => {
  if (typeof change === 'string') {
    return {
      descricao: change,
      testes: [],
      criterios_aceite: []
    };
  }

  const c = asObj(change);
  return {
    descricao: String(c.descricao || c.desc || c.description || '').trim(),
    testes: toArray(c.testes || c.tests || c.test_steps).map((x) => String(x || '').trim()).filter(Boolean),
    criterios_aceite: toArray(c.criterios_aceite || c.acceptance_criterias || c.acceptance_criteria).map((x) => String(x || '').trim()).filter(Boolean)
  };
};

const impactByKey = new Map(
  Object.entries(asObj(impacts)).map(([k, v]) => [normalize(k), asObj(v)])
);

const findImpactForRepo = (repoName) => {
  const n = normalize(repoName);
  const candidates = [n, n.replaceAll('_', '-'), n.replaceAll('-', '_')];

  if (n.includes('domain')) candidates.push('fastroute-domain', 'domain');
  if (n.includes('api')) candidates.push('fastroute-api', 'fastroute_api', 'api');
  if (n.includes('mobile')) candidates.push('fastroute-mobile-hybrid', 'mobile');

  for (const c of candidates) {
    const hit = impactByKey.get(normalize(c));
    if (hit) return hit;
  }

  return {};
};

const repos = $input.all().map((i) => i.json).filter((r) => r && r.name);
const out = [];

for (const repo of repos) {
  const repoId = [repo.repo_id, repo.id, repo['\uFEFFid']]
    .map(toSafeNumber)
    .find((n) => Number.isFinite(n));

  if (!Number.isFinite(repoId)) {
    continue;
  }

  const impactInfo = asObj(findImpactForRepo(repo.name));
  const impacted = impactInfo.impacto === true || impactInfo.impact === true || impactInfo.has_impact === true;
  if (!impacted) continue;

  const changes = toArray(impactInfo.mudancas || impactInfo.changes).map(normalizeChange);
  const changeRisks = toArray(impactInfo.riscos || impactInfo.risks).map((x) => String(x || '').trim()).filter(Boolean);
  const changeDoubts = toArray(impactInfo.duvidas || impactInfo.doubts).map((x) => String(x || '').trim()).filter(Boolean);

  const normalizedChanges = changes.length > 0
    ? changes
    : [{
        descricao: analysisId
          ? '[impact:' + analysisId + '] Mudanca sem detalhamento fornecido pelo LLM'
          : 'Mudanca sem detalhamento fornecido pelo LLM',
        testes: [],
        criterios_aceite: []
      }];

  for (const change of normalizedChanges) {
    const desc = String(change.descricao || '').trim() || 'Mudanca sem descricao';
    const criteria = toArray(change.criterios_aceite).map((x) => String(x || '').trim()).filter(Boolean);
    const summaryBase = analysisId ? '[impact:' + analysisId + '] ' + desc : desc;
    const summary = criteria.length > 0
      ? summaryBase + ' | criterios_aceite: ' + criteria.join(' | ')
      : summaryBase;

    out.push({
      repo_id: repoId,
      repo_name: repo.name,
      change_summary: summary,
      test_steps: toArray(change.testes).map((x) => String(x || '').trim()).filter(Boolean),
      acceptance_criteria: criteria,
      change_risks: changeRisks,
      change_doubts: changeDoubts,
      impact_analysis_id: analysisId,
    });
  }
}

if (out.length === 0) {
  return [{ json: { skip_repo_persistence: true } }];
}

return out.map((json) => ({ json }));

const insertedChanges = $input.all();
if (insertedChanges.length === 0) {
  return [{ json: { skip_test_persistence: true } }];
}

const sourceRows = $items('Build Change Rows', 0, 0).map((i) => i.json || {});
const makeKey = (repoId, changeSummary) => Number(repoId) + '::' + String(changeSummary || '').trim();

const sourceByKey = new Map();
for (const source of sourceRows) {
  sourceByKey.set(makeKey(source.repo_id, source.change_summary), source);
}

const out = [];
for (const item of insertedChanges) {
  const inserted = item.json || {};
  const key = makeKey(inserted.repo_id, inserted.change_summary);
  const source = sourceByKey.get(key);

  const steps = Array.isArray(source?.test_steps)
    ? source.test_steps.map((x) => String(x || '').trim()).filter(Boolean)
    : [];

  if (steps.length === 0) {
    continue;
  }

  out.push({
    json: {
      change_id: Number(inserted.id),
      change_summary: String(inserted.change_summary || ''),
      test_steps: steps,
    },
  });
}

if (out.length === 0) {
  return [{ json: { skip_test_persistence: true } }];
}

return out;

const insertedTests = $input.all().map((i) => i.json).filter((r) => r && r.id !== undefined && r.change_id !== undefined);
if (insertedTests.length === 0) {
  return [];
}

const sourceTests = $items('Build Test Rows', 0, 0).map((i) => i.json || {});
const stepsByChangeId = new Map();

for (const source of sourceTests) {
  const changeId = String(source.change_id);
  const steps = Array.isArray(source.test_steps)
    ? source.test_steps.map((x) => String(x || '').trim()).filter(Boolean)
    : [];

  if (!stepsByChangeId.has(changeId)) {
    stepsByChangeId.set(changeId, steps);
  }
}

const out = [];
for (const inserted of insertedTests) {
  const changeId = String(inserted.change_id);
  const steps = stepsByChangeId.get(changeId) || [];

  for (const description of steps) {
    out.push({
      json: {
        testsuite_id: Number(inserted.id),
        description,
      },
    });
  }
}

return out;

const base = $items('Parse LLM JSON', 0, 0)?.[0]?.json || {};
const impactInsert = $items('Insert Impact Analysis', 0, 0)?.[0]?.json || {};

return [{
  json: {
    ...base,
    impact_analysis_id: impactInsert.id || null,
    persisted_at: new Date().toISOString(),
  }
}];

const decision = $items('Parse Decision', 0, 0)?.[0]?.json || {};

const analysisId = Number(decision.analysis_id);
if (!Number.isFinite(analysisId)) {
  return [{
    approved: false,
    ...decision,
    impact_analysis: {
      parse_error: true,
      observacao: 'analysis_id invalido ou ausente.'
    }
  }];
}

const uniqById = (rows) => {
  const out = new Map();
  for (const row of rows) {
    const key = row && row.id !== undefined ? String(row.id) : JSON.stringify(row);
    if (!out.has(key)) out.set(key, row);
  }
  return [...out.values()];
};

const impactRows = uniqById($items('Decision Load Impact Analysis', 0, 0).map((i) => i.json || {}));
const repoRows = uniqById($items('Decision Load Repos', 0, 0).map((i) => i.json || {}));
const changeRows = uniqById($items('Decision Load Changes', 0, 0).map((i) => i.json || {}));
const testsuiteRows = uniqById($items('Decision Load Testsuites', 0, 0).map((i) => i.json || {}));
const testStepRows = uniqById($items('Decision Load Tests For Testsuite', 0, 0).map((i) => i.json || {}));

const impactRow = impactRows.find((r) => Number(r.id) === analysisId);
if (!impactRow) {
  return [{
    approved: false,
    ...decision,
    impact_analysis: {
      not_found: true,
      observacao: 'Nao foi encontrada linha em impact_analysis para o analysis_id informado.'
    }
  }];
}

const repoNameById = new Map(
  repoRows
    .filter((r) => r && r.id !== undefined && r.name)
    .map((r) => [Number(r.id), String(r.name)])
);

const prefix = '[impact:' + analysisId + ']';
const impactedChanges = changeRows.filter((r) => String(r.change_summary || '').includes(prefix));

const impacts = {};
for (const [id, name] of repoNameById.entries()) {
  impacts[name] = { impacto: false, mudancas: [], riscos: [], duvidas: [] };
}

const criteriaMapped = [];

for (const change of impactedChanges) {
  const repoId = Number(change.repo_id);
  const repoName = repoNameById.get(repoId) || ('repo-' + String(repoId));
  if (!impacts[repoName]) {
    impacts[repoName] = { impacto: false, mudancas: [], riscos: [], duvidas: [] };
  }

  let summary = String(change.change_summary || '').trim();
  if (summary.includes(prefix)) {
    summary = summary.replace(prefix, '').trim();
  }

  const marker = '| criterios_aceite:';
  let descricao = summary;
  let criterios = [];
  if (summary.includes(marker)) {
    const parts = summary.split(marker);
    descricao = String(parts.shift() || '').trim();
    criterios = parts.join(marker).split('|').map((x) => String(x || '').trim()).filter(Boolean);
  }

  const suites = testsuiteRows.filter((t) => Number(t.change_id) === Number(change.id));
  const suiteIds = new Set(suites.map((s) => Number(s.id)).filter((id) => Number.isFinite(id)));

  const tests = testStepRows
    .filter((s) => suiteIds.has(Number(s.testsuite_id)))
    .map((s) => String(s.description || '').trim())
    .filter(Boolean);

  const uniqueTests = [...new Set(tests)];

  impacts[repoName].impacto = true;
  impacts[repoName].mudancas.push({
    descricao: descricao || 'Mudanca sem descricao',
    testes: uniqueTests,
    criterios_aceite: criterios,
  });

  for (const criterio of criterios) {
    criteriaMapped.push({
      criterio,
      repos: [repoName],
      teste_sugerido: uniqueTests[0] || '',
    });
  }
}

if (!impacts.infra) impacts.infra = { impacto: false, itens: [] };
if (!impacts.integracoes_externas) impacts.integracoes_externas = { impacto: false, itens: [] };

const impactAnalysis = {
  resumo: String(impactRow.change_summary || 'Sem resumo'),
  viabilidade: {
    nivel: String(impactRow.complexity_level || 'Media'),
    justificativa: 'Reconstruida a partir das data-tables via analysis_id.'
  },
  impactos: impacts,
  criterios_aceite_mapeados: criteriaMapped,
  riscos: [],
  duvidas: [],
  source_analysis_id: analysisId,
};

return [{
  approved: true,
  owner: decision.owner,
  repo: decision.repo,
  github_token: decision.github_token,
  deploy_api: decision.deploy_api,
  domain_ref: decision.domain_ref,
  api_ref: decision.api_ref,
  mobile_ref: decision.mobile_ref,
  mobile_profile: decision.mobile_profile,
  impact_analysis: impactAnalysis
}];

const toSafeNumber = (value) => {
  if (value === undefined || value === null) return NaN;
  const s = String(value).replace(/^\uFEFF/, '').trim();
  if (!s) return NaN;
  const n = Number(s);
  return Number.isFinite(n) ? n : NaN;
};

const repoId = toSafeNumber($json.repo_id);
if (!Number.isFinite(repoId)) {
  return [];
}

return [{
  json: {
    ...$json,
    repo_id: repoId,
  },
}];
